INSERT INTO interview_analyses (id, candidate_id, schedule_id, recording_id, interview_type, transcription, transcription_segments, ai_summary, key_answers, communication_score, expertise_score, attitude_score, overall_score, strengths, concerns, overall_impression, ai_interviewer_session, ai_interviewer_questions, real_time_emotions, real_time_flags, real_time_voice, ai_provider, ai_model, status, error_message, analyzed_at, created_at, updated_at, confirmed_at, file_deleted)
VALUES (
  E'683a6605-5dcb-4a69-94d3-a7890fcf44f3',
  E'f801b37d-f4d5-4b2c-bb10-26295ea3c6e4',
  E'57055d6a-3276-488c-8895-8eed6dba017d',
  E'b26f9926-f4db-44c7-a73f-f85f091c4f36',
