SELECT id, candidate_id, interview_type, status, overall_score, ai_provider, created_at FROM interview_analyses ORDER BY created_at;

-- Detail: recruitment_reports
SELECT id, candidate_id, report_type, overall_score, ai_recommendation, created_at FROM recruitment_reports ORDER BY created_at;

-- FK referential integrity check
SELECT ia.id, ia.recording_id, ir.id AS matched_recording
FROM interview_analyses ia
LEFT JOIN interview_recordings ir ON ia.recording_id = ir.id
WHERE ir.id IS NULL AND ia.recording_id IS NOT NULL;
